162→+/// Send a document payload to all pending channel targets for a session.
163→+/// Uses `peek_channel_replies` so targets remain for the final text response.
164→+async fn dispatch_document_to_channels(
165→+    state: &Arc<dyn ChatRuntime>,
166→+    session_key: &str,
167→+    payload: moltis_common::types::ReplyPayload,
168→+) {
169→+    let targets = state.peek_channel_replies(session_key).await;
170→+    if targets.is_empty() {
171→+        return;
172→+    }
173→+
174→+    let outbound = match state.channel_outbound() {
175→+        Some(o) => o,
176→+        None => return,
177→+    };
178→+
179→+    let mut tasks = Vec::with_capacity(targets.len());
180→+    for target in targets {
181→+        let outbound = Arc::clone(&outbound);
182→+        let payload = payload.clone();
183→+        tasks.push(tokio::spawn(async move {
184→+            let reply_to = target.message_id.as_deref();
185→+            if let Err(e) = outbound
186→+                .send_media(&target.account_id, &target.chat_id, &payload, reply_to)
187→+                .await
188→+            {
189→+                warn!(
190→+                    account_id = target.account_id,
191→+                    chat_id = target.chat_id,
192→+                    "failed to send document to channel: {e}"
193→+                );
194→+                let error_msg = format!("\u{26a0}\u{fe0f} Failed to send document: {e}");
195→+                let _ = outbound
196→+                    .send_text(&target.account_id, &target.chat_id, &error_msg, reply_to)
197→+                    .await;
198→+            } else {
199→+                debug!(
200→+                    account_id = target.account_id,
201→+                    chat_id = target.chat_id,
202→+                    "sent document to channel"
203→+                );
204→+            }
205→+        }));
206→+    }
207→+
208→+    for task in tasks {
209→+        if let Err(e) = task.await {
210→+            warn!(error = %e, "channel document task join failed");
211→+        }
212→+    }
213→+}
