+/// Map a MIME type to its canonical file extension.
 pub fn extension_for_mime(mime: &str) -> &str {
     match mime {
+        // Images
         "image/jpeg" => "jpg",
         "image/png" => "png",
         "image/gif" => "gif",
         "image/webp" => "webp",
+        "image/x-portable-pixmap" => "ppm",
+        // Audio / Video
         "audio/ogg" => "ogg",
         "audio/mpeg" => "mp3",
+        "audio/webm" => "webm",
         "video/mp4" => "mp4",
+        // Documents
+        "application/pdf" => "pdf",
+        "text/plain" => "txt",
+        "text/csv" => "csv",
+        "application/json" => "json",
+        "application/zip" => "zip",
+        "application/gzip" => "gz",
+        "application/vnd.openxmlformats-officedocument.wordprocessingml.document" => "docx",
+        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" => "xlsx",
+        "application/vnd.openxmlformats-officedocument.presentationml.presentation" => "pptx",
+        "application/vnd.ms-excel" => "xls",
+        "application/msword" => "doc",
+        "text/html" => "html",
+        "text/xml" | "application/xml" => "xml",
+        "application/rtf" => "rtf",
+        "text/markdown" => "md",
         _ => "bin",
     }
 }
+
+/// Map a file extension (without leading dot) to its MIME type.
+pub fn mime_from_extension(ext: &str) -> Option<&'static str> {
+    match ext.to_ascii_lowercase().as_str() {
+        // Images
+        "png" => Some("image/png"),
+        "jpg" | "jpeg" => Some("image/jpeg"),
+        "gif" => Some("image/gif"),
+        "webp" => Some("image/webp"),
+        "ppm" => Some("image/x-portable-pixmap"),
+        // Documents
+        "pdf" => Some("application/pdf"),
+        "txt" | "text" | "log" => Some("text/plain"),
+        "csv" => Some("text/csv"),
+        "json" => Some("application/json"),
+        "zip" => Some("application/zip"),
+        "gz" | "gzip" => Some("application/gzip"),
+        "docx" => Some("application/vnd.openxmlformats-officedocument.wordprocessingml.document"),
+        "xlsx" => Some("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"),
+        "pptx" => Some("application/vnd.openxmlformats-officedocument.presentationml.presentation"),
+        "xls" => Some("application/vnd.ms-excel"),
+        "doc" => Some("application/msword"),
+        "html" | "htm" => Some("text/html"),
+        "xml" => Some("application/xml"),
+        "rtf" => Some("application/rtf"),
+        "md" | "markdown" => Some("text/markdown"),
+        // Audio / Video
+        "ogg" | "oga" => Some("audio/ogg"),
+        "mp3" => Some("audio/mpeg"),
+        "mp4" => Some("video/mp4"),
+        "webm" => Some("audio/webm"),
+        _ => None,
+    }
+}
