601→+//! Shared file-reading logic for tools that read from host or sandbox filesystems.
602→+//!
603→+//! Used by `send_image` and `send_document` to read files consistently,
604→+//! with sandbox routing and size validation.
605→+
606→+use {
607→+    base64::{Engine as _, engine::general_purpose::STANDARD as BASE64},
608→+    std::{path::PathBuf, sync::Arc, time::Duration},
609→+    tracing::warn,
610→+};
611→+
612→+use crate::{Result, error::Error, exec::ExecOpts, sandbox::SandboxRouter};
613→+
614→+/// 20 MB — Telegram's maximum file upload size.
615→+pub const MAX_FILE_SIZE: u64 = 20 * 1024 * 1024;
616→+
617→+/// Enough for a 20 MB binary file encoded as base64 (~26.7 MB) plus margin.
618→+pub const MAX_SANDBOX_OUTPUT_BYTES: usize = 32 * 1024 * 1024;
619→+
620→+/// Prefix emitted by the sandbox script when the file exceeds the size limit.
621→+pub const SANDBOX_TOO_LARGE_PREFIX: &str = "__MOLTIS_FILE_TOO_LARGE__:";
622→+
623→+/// Read a file from the host filesystem with size validation.
624→+pub async fn read_host_file(path: &str) -> Result<Vec<u8>> {
625→+    let meta = tokio::fs::metadata(path)
626→+        .await
627→+        .map_err(|e| Error::message(format!("cannot access '{path}': {e}")))?;
628→+
629→+    if !meta.is_file() {
630→+        return Err(Error::message(format!("'{path}' is not a regular file")));
631→+    }
632→+
633→+    if meta.len() > MAX_FILE_SIZE {
634→+        return Err(Error::message(format!(
635→+            "file is too large ({:.1} MB) — maximum is {:.0} MB",
636→+            meta.len() as f64 / (1024.0 * 1024.0),
637→+            MAX_FILE_SIZE as f64 / (1024.0 * 1024.0),
638→+        )));
639→+    }
640→+
641→+    let bytes = tokio::fs::read(path)
642→+        .await
643→+        .map_err(|e| Error::message(format!("failed to read '{path}': {e}")))?;
644→+
645→+    // Post-read size guard against TOCTOU races.
646→+    if bytes.len() as u64 > MAX_FILE_SIZE {
647→+        return Err(Error::message(format!(
648→+            "file is too large ({:.1} MB) — maximum is {:.0} MB",
649→+            bytes.len() as f64 / (1024.0 * 1024.0),
650→+            MAX_FILE_SIZE as f64 / (1024.0 * 1024.0),
651→+        )));
652→+    }
653→+
654→+    Ok(bytes)
655→+}
656→+
657→+/// Read a file from a sandbox container, returning the raw bytes.
658→+pub async fn read_sandbox_file(
659→+    router: &SandboxRouter,
660→+    session_key: &str,
661→+    path: &str,
662→+) -> Result<Vec<u8>> {
663→+    let sandbox_id = router.sandbox_id_for(session_key);
664→+    let image = router.resolve_image(session_key, None).await;
665→+    let backend = router.backend();
666→+    backend.ensure_ready(&sandbox_id, Some(&image)).await?;
667→+
668→+    let quoted_path = shell_single_quote(path);
669→+    let command = format!(
670→+        "if [ ! -f {quoted_path} ]; then \
671→+             echo \"path is not a regular file\" >&2; \
672→+             exit 2; \
673→+         fi; \
674→+         size=$(wc -c < {quoted_path}); \
675→+         if [ \"$size\" -gt {MAX_FILE_SIZE} ]; then \
676→+             echo \"{SANDBOX_TOO_LARGE_PREFIX}$size\" >&2; \
677→+             exit 3; \
678→+         fi; \
679→+         base64 < {quoted_path} | tr -d '\\n'"
680→+    );
681→+
682→+    let opts = ExecOpts {
683→+        timeout: Duration::from_secs(30),
684→+        max_output_bytes: MAX_SANDBOX_OUTPUT_BYTES,
685→+        working_dir: Some(PathBuf::from("/home/sandbox")),
686→+        env: Vec::new(),
687→+    };
688→+
689→+    let result = backend.exec(&sandbox_id, &command, &opts).await?;
690→+    if result.exit_code != 0 {
691→+        if let Some(size_str) = result
692→+            .stderr
693→+            .lines()
694→+            .find_map(|line| line.strip_prefix(SANDBOX_TOO_LARGE_PREFIX))
695→+            && let Ok(size) = size_str.trim().parse::<u64>()
696→+        {
697→+            return Err(Error::message(format!(
698→+                "file is too large ({:.1} MB) — maximum is {:.0} MB",
699→+                size as f64 / (1024.0 * 1024.0),
700→+                MAX_FILE_SIZE as f64 / (1024.0 * 1024.0),
701→+            )));
702→+        }
703→+
704→+        let detail = if !result.stderr.trim().is_empty() {
705→+            result.stderr.trim().to_string()
706→+        } else if !result.stdout.trim().is_empty() {
707→+            result.stdout.trim().to_string()
708→+        } else {
709→+            format!("sandbox command failed with exit code {}", result.exit_code)
710→+        };
711→+        return Err(Error::message(format!(
712→+            "cannot access '{path}' in sandbox: {detail}"
713→+        )));
714→+    }
715→+
716→+    let bytes = BASE64
717→+        .decode(result.stdout.trim())
718→+        .map_err(|e| Error::message(format!("failed to decode sandbox file '{path}': {e}")))?;
719→+
720→+    if bytes.len() as u64 > MAX_FILE_SIZE {
721→+        return Err(Error::message(format!(
722→+            "file is too large ({:.1} MB) — maximum is {:.0} MB",
723→+            bytes.len() as f64 / (1024.0 * 1024.0),
724→+            MAX_FILE_SIZE as f64 / (1024.0 * 1024.0),
725→+        )));
726→+    }
727→+
728→+    Ok(bytes)
729→+}
730→+
731→+/// Read a file for a session, routing through sandbox if the session is sandboxed.
732→+pub async fn read_file_for_session(
733→+    sandbox_router: Option<&Arc<SandboxRouter>>,
734→+    session_key: &str,
735→+    path: &str,
736→+    tool_name: &str,
737→+) -> Result<Vec<u8>> {
738→+    let Some(router) = sandbox_router else {
739→+        return read_host_file(path).await;
740→+    };
741→+
742→+    if !router.is_sandboxed(session_key).await {
743→+        return read_host_file(path).await;
744→+    }
745→+
746→+    match read_sandbox_file(router, session_key, path).await {
747→+        Ok(bytes) => Ok(bytes),
748→+        Err(error) => {
749→+            warn!(
750→+                session_key,
751→+                path,
752→+                error = %error,
753→+                "{tool_name} failed to read from sandbox"
754→+            );
755→+            Err(error)
756→+        },
757→+    }
758→+}
