1856→+/// Build a `Content-Disposition` header value for a media file.
1857→+/// Uses `inline` for types browsers can render natively (PDF, text, HTML,
1858→+/// images) and `attachment` for everything else so they trigger a download.
1859→+fn media_content_disposition(filename: &str, content_type: &str) -> String {
1860→+    let inline = content_type.starts_with("image/")
1861→+        || content_type.starts_with("audio/")
1862→+        || matches!(
1863→+            content_type,
1864→+            "application/pdf" | "text/plain" | "text/html" | "text/csv" | "text/markdown"
1865→+        );
1866→+    let disposition = if inline {
1867→+        "inline"
1868→+    } else {
1869→+        "attachment"
1870→+    };
1871→+    // Sanitise filename for the header (strip quotes, newlines, semicolons,
1872→+    // backslashes — all of which can break or inject Content-Disposition).
1873→+    let safe_name: String = filename
1874→+        .chars()
1875→+        .filter(|c| *c != '"' && *c != '\n' && *c != '\r' && *c != ';' && *c != '\\')
1876→+        .collect();
1877→+    format!("{disposition}; filename=\"{safe_name}\"")
1878→+}
